using UnityEngine;
using FL.Gameplay.Vehicle;
using FL.Gameplay.Modules.BigWorld;
public class Script
{
    public static object Main()
    {
        try
        {
            var player = PlayerManager.Controller;
            if (player == null) return "No player";
            var playerPos = player.GetTransform().position;
            var result = "PlayerPos=" + playerPos + "\n";
            var allControllers = Object.FindObjectsOfType<MonoBehaviour>();
            int vCount = 0;
            foreach (var mb in allControllers)
            {
                if (mb is Vehicle v)
                {
                    vCount++;
                    var dist = UnityEngine.Vector3.Distance(v.transform.position, playerPos);
                    if (vCount <= 5)
                        result += "Vehicle: " + v.name + " dist=" + dist.ToString("F1") + " isTraffic=" + v.isControlledByTraffic + " pos=" + v.transform.position + "\n";
                }
            }
            result += "Total Vehicles: " + vCount;
            return result;
        }
        catch (System.Exception ex) { return "Error: " + ex.Message; }
    }
}
